    constructor(n) {
        this.n = n;
        this.tree = new Array(n + 1).fill(0);
    }

    update(i, delta) {
        i++;
        while (i <= this.n) {
            this.tree[i] += delta;
            i += i & -i;
        }
    }

    prefixQuery(i) {
        i++;
        if (i > this.n) i = this.n;
        let res = 0;
        while (i > 0) {
            res += this.tree[i];
            i -= i & -i;
        }
        return res;
    }

    rangeQuery(l, r) {
        if (l > r) return 0;
        const leftSum = l > 0 ? this.prefixQuery(l - 1) : 0;
        const rightSum = this.prefixQuery(r);
        return rightSum - leftSum;
    }
}

