    function computeDepth(x) {
        if (depthCache.has(x)) {
            return depthCache.get(x);
        }
        const path = [];
        let cur = x;
        while (!depthCache.has(cur)) {
            path.push(cur);
            if (cur === 1) break;
            cur = popcount(cur);
        }
        let depth = depthCache.get(cur);
        for (let i = path.length - 1; i >= 0; i--) {
            depth++;
            depthCache.set(path[i], depth);
